(function(w){"use strict";const ID="pressure-formula";function compute(x){const f=Number(x.force),a=Number(x.area);if(!Number.isFinite(f)||!Number.isFinite(a)||a<=0)return{error:"힘과 0보다 큰 면적을 입력해 주세요."};return{value:f/a};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>힘 (N)</label><input class="hm-calc-input" inputmode="decimal" data-key="force" placeholder="" value=""></div><div class="hm-calc-field"><label>면적 (m²)</label><input class="hm-calc-input" inputmode="decimal" data-key="area" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("압력",`${api.formatNumber(r.value,8)} Pa`,"P = F ÷ A"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
